mapper.select:
/** BsnsClDao.selectList */ select bsns_cl_id , parent_bsns_cl_id , bsns_cl_nm , sort_order , enabled , creator_id , created_dt , updater_id , updated_dt from uspt_bsns_cl
and parent_bsns_cl_id = #{parentBsnsClId}
and parent_bsns_cl_id is null

mapper.insert:
insert into uspt_bsns_cl(bsns_cl_id
						, parent_bsns_cl_id
						, bsns_cl_nm
						, sort_order
						, enabled
						, creator_id
						, created_dt
						, updater_id
						, updated_dt)
				values	(#{bsnsClId}
						, #{parentBsnsClId}
						, #{bsnsClNm}
						, #{sortOrder}
						, #{enabled}
						, #{creatorId}
						, #{createdDt}
						, #{updaterId}
						, #{updatedDt}
						)

mapper.update:
/** BsnsClDao.update */
update uspt_bsns_cl
set
	bsns_cl_nm		= #{bsnsClNm}
	, sort_order	= #{sortOrder}
	, enabled		= #{enabled}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
where
	bsns_cl_id = #{bsnsClId}

mapper.delete:
/** BsnsClDao.delete */
delete from uspt_bsns_cl
where
	bsns_cl_id = #{bsnsClId}

